            ctx.fillStyle = 'rgba(22, 33, 62, 0.7)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = config.colors.text;
            ctx.font = 'bold 32px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText(title, canvas.width / 2, canvas.height / 2 - 20);

            ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText(subtitle, canvas.width / 2, canvas.height / 2 + 20);
        }

        // 更新分数显示
        function updateScoreDisplay() {
            currentScoreElement.textContent = gameState.score;

            // 更新最高分
            if (gameState.score > gameState.highScore) {
                gameState.highScore = gameState.score;
                localStorage.setItem('snakeHighScore', gameState.highScore);
            }

            highScoreElement.textContent = gameState.highScore;
        }

        // 游戏结束
        function gameOver() {
            gameState.current = 'gameover';

            if (gameState.gameLoopId) {
                cancelAnimationFrame(gameState.gameLoopId);
                gameState.gameLoopId = null;
            }
        }

        // 处理输入
        function handleInput(key, pressed) {
            if (!pressed) return;

            switch (key) {
                case 'ArrowUp':
                case 'w':
                case 'W':
                    if (snake.direction !== 'down') {
                        snake.nextDirection = 'up';
                    }
                    break;
                case 'ArrowDown':
                case 's':
                case 'S':
                    if (snake.direction !== 'up') {
                        snake.nextDirection = 'down';
                    }
                    break;
                case 'ArrowLeft':
                case 'a':
                case 'A':
                    if (snake.direction !== 'right') {
                        snake.nextDirection = 'left';
                    }
                    break;
                case 'ArrowRight':
                case 'd':
                case 'D':
                    if (snake.direction !== 'left') {
                        snake.nextDirection = 'right';
                    }
                    break;
                case ' ':
                    // 空格键处理
                    if (gameState.current === 'menu' || gameState.current === 'gameover') {
                        initGame();
                    } else if (gameState.current === 'playing') {
                        gameState.current = 'paused';
                    } else if (gameState.current === 'paused') {
                        gameState.current = 'playing';
                        gameState.lastUpdateTime = performance.now();
                    }
                    break;
            }
        }

        // 游戏循环
        function gameLoop(currentTime) {
            gameState.gameLoopId = requestAnimationFrame(gameLoop);

            const deltaTime = currentTime - gameState.lastUpdateTime;

            // 控制游戏速度
            if (deltaTime >= snake.speed) {
                update(deltaTime);
                gameState.lastUpdateTime = currentTime;
            }

            render();
        }

        // 键盘事件监听
        document.addEventListener('keydown', (e) => {
            handleInput(e.key, true);

            // 阻止方向键滚动页面
            if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].includes(e.key)) {
                e.preventDefault();
            }
        });

        // 初始化显示
        updateScoreDisplay();

        // 开始游戏循环（显示菜单）
        gameState.gameLoopId = requestAnimationFrame(gameLoop);
    </script>
