                    ctx.lineWidth = 2;
                    ctx.strokeRect(x, y, config.gridSize, config.gridSize);

                    // 为蛇头添加眼睛
                    if (index === 0) {
                        ctx.fillStyle = 'white';
                        const eyeSize = config.gridSize / 5;
                        const eyeOffset = config.gridSize / 3;

                        // 根据方向调整眼睛位置
                        let leftEyeX, leftEyeY, rightEyeX, rightEyeY;

                        switch (snake.direction) {
                            case 'up':
                                leftEyeX = x + eyeOffset;
                                leftEyeY = y + eyeOffset;
                                rightEyeX = x + config.gridSize - eyeOffset - eyeSize;
                                rightEyeY = y + eyeOffset;
                                break;
                            case 'down':
                                leftEyeX = x + eyeOffset;
                                leftEyeY = y + config.gridSize - eyeOffset - eyeSize;
                                rightEyeX = x + config.gridSize - eyeOffset - eyeSize;
                                rightEyeY = y + config.gridSize - eyeOffset - eyeSize;
                                break;
                            case 'left':
                                leftEyeX = x + eyeOffset;
                                leftEyeY = y + eyeOffset;
                                rightEyeX = x + eyeOffset;
                                rightEyeY = y + config.gridSize - eyeOffset - eyeSize;
                                break;
                            case 'right':
                                leftEyeX = x + config.gridSize - eyeOffset - eyeSize;
                                leftEyeY = y + eyeOffset;
                                rightEyeX = x + config.gridSize - eyeOffset - eyeSize;
                                rightEyeY = y + config.gridSize - eyeOffset - eyeSize;
                                break;
                        }

                        ctx.fillRect(leftEyeX, leftEyeY, eyeSize, eyeSize);
                        ctx.fillRect(rightEyeX, rightEyeY, eyeSize, eyeSize);
                    }
                });

                // 绘制食物
                const foodX = food.position.x * config.gridSize;
                const foodY = food.position.y * config.gridSize;

                ctx.fillStyle = config.colors.food;
                ctx.beginPath();
                ctx.arc(
                    foodX + config.gridSize / 2,
                    foodY + config.gridSize / 2,
                    config.gridSize / 2 - 2,
                    0,
                    Math.PI * 2
                );
                ctx.fill();

                ctx.strokeStyle = config.colors.foodBorder;
                ctx.lineWidth = 2;
                ctx.stroke();

                // 绘制暂停界面
                if (gameState.current === 'paused') {
                    drawOverlay('游戏暂停', '按空格键继续');
                }
            } else if (gameState.current === 'menu') {
                drawMenu();
            } else if (gameState.current === 'gameover') {
                drawGameOver();
            }
        }

        // 绘制菜单界面
        function drawMenu() {
            // 半透明遮罩
            ctx.fillStyle = config.colors.menuBackground;
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // 标题
            ctx.fillStyle = config.colors.text;
            ctx.font = 'bold 36px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('贪吃蛇游戏', canvas.width / 2, canvas.height / 2 - 60);

            // 说明
            ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText('按空格键开始游戏', canvas.width / 2, canvas.height / 2);

            // 操作说明
            ctx.font = '14px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillStyle = 'rgba(255, 255, 255, 0.7)';
            ctx.fillText('方向键或WASD控制移动', canvas.width / 2, canvas.height / 2 + 40);
            ctx.fillText('空格键暂停游戏', canvas.width / 2, canvas.height / 2 + 65);

            // 显示最高分
            ctx.fillStyle = config.colors.snakeHead;
            ctx.font = 'bold 20px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText(`最高分: ${gameState.highScore}`, canvas.width / 2, canvas.height / 2 + 110);
        }

        // 绘制游戏结束界面
        function drawGameOver() {
            // 半透明遮罩
            ctx.fillStyle = 'rgba(22, 33, 62, 0.9)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // 游戏结束标题
            ctx.fillStyle = config.colors.food;
            ctx.font = 'bold 36px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('游戏结束', canvas.width / 2, canvas.height / 2 - 60);

            // 显示分数
            ctx.fillStyle = config.colors.text;
            ctx.font = '24px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText(`得分: ${gameState.score}`, canvas.width / 2, canvas.height / 2);

            // 显示最高分
            ctx.fillStyle = config.colors.snakeHead;
            ctx.font = '20px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText(`最高分: ${gameState.highScore}`, canvas.width / 2, canvas.height / 2 + 40);

            // 重新开始提示
            ctx.fillStyle = config.colors.text;
            ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText('按空格键重新开始', canvas.width / 2, canvas.height / 2 + 100);
        }

        // 绘制覆盖层（用于暂停等）
        function drawOverlay(title, subtitle) {
            ctx.fillStyle = 'rgba(22, 33, 62, 0.7)';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            ctx.fillStyle = config.colors.text;
            ctx.font = 'bold 32px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText(title, canvas.width / 2, canvas.height / 2 - 20);

            ctx.font = '18px "PingFang SC", "Microsoft YaHei", sans-serif';
            ctx.fillText(subtitle, canvas.width / 2, canvas.height / 2 + 20);
        }

        // 更新分数显示
        function updateScoreDisplay() {
            currentScoreElement.textContent = gameState.score;

            // 更新最高分
            if (gameState.score > gameState.highScore) {
                gameState.highScore = gameState.score;
                localStorage.setItem('snakeHighScore', gameState.highScore);
            }

            highScoreElement.textContent = gameState.highScore;
        }

        // 游戏结束
        function gameOver() {
            gameState.current = 'gameover';

            if (gameState.gameLoopId) {
                cancelAnimationFrame(gameState.gameLoopId);
                gameState.gameLoopId = null;
            }
        }

        // 处理输入
        function handleInput(key, pressed) {
            if (!pressed) return;

            switch (key) {
                case 'ArrowUp':
                case 'w':
                case 'W':
                    if (snake.direction !== 'down') {
                        snake.nextDirection = 'up';
                    }
                    break;
                case 'ArrowDown':
                case 's':
                case 'S':
                    if (snake.direction !== 'up') {
                        snake.nextDirection = 'down';
                    }
                    break;
                case 'ArrowLeft':
                case 'a':
                case 'A':
                    if (snake.direction !== 'right') {
                        snake.nextDirection = 'left';
                    }
                    break;
                case 'ArrowRight':
                case 'd':
                case 'D':
                    if (snake.direction !== 'left') {
                        snake.nextDirection = 'right';
                    }
                    break;
                case ' ':
                    // 空格键处理
                    if (gameState.current === 'menu' || gameState.current === 'gameover') {
                        initGame();
                    } else if (gameState.current === 'playing') {
                        gameState.current = 'paused';
                    } else if (gameState.current === 'paused') {
                        gameState.current = 'playing';
                        gameState.lastUpdateTime = performance.now();
                    }
                    break;
            }
        }

        // 游戏循环
        function gameLoop(currentTime) {
            gameState.gameLoopId = requestAnimationFrame(gameLoop);

            const deltaTime = currentTime - gameState.lastUpdateTime;

            // 控制游戏速度
            if (deltaTime >= snake.speed) {
                update(deltaTime);
                gameState.lastUpdateTime = currentTime;
            }

            render();
        }

        // 键盘事件监听
        document.addEventListener('keydown', (e) => {
            handleInput(e.key, true);

            // 阻止方向键滚动页面
            if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight', ' '].includes(e.key)) {
                e.preventDefault();
            }
        });

        // 初始化显示
        updateScoreDisplay();

        // 开始游戏循环（显示菜单）
        gameState.gameLoopId = requestAnimationFrame(gameLoop);
    </script>
